"use strict";(self.webpackChunksite=self.webpackChunksite||[]).push([["4137"],{67810(e,n,i){i.r(n),i.d(n,{metadata:()=>r,default:()=>o,frontMatter:()=>a,contentTitle:()=>u,toc:()=>d,assets:()=>l});var r=JSON.parse('{"id":"publikationen/reformvorschlag-konjunkturkomponente-schuldenbremse","title":"Ein Reformvorschlag f\xfcr die Konjunkturkomponente der Schuldenbremse","description":"Was ist die Konjunkturkomponente? Die Konjunkturkomponente ist der Teil der Schuldenbremse, der die maximal zul\xe4ssige Nettokreditaufnahme (NKA) bei einer von der Normallage abweichenden","source":"@site/docs/publikationen/reformvorschlag-konjunkturkomponente-schuldenbremse.md","sourceDirName":"publikationen","slug":"/publikationen/reformvorschlag-konjunkturkomponente-schuldenbremse","permalink":"/dz-publikationsgraph/wiki/publikationen/reformvorschlag-konjunkturkomponente-schuldenbremse","draft":false,"unlisted":false,"tags":[{"inline":true,"label":"konjunkturkomponente","permalink":"/dz-publikationsgraph/wiki/tags/konjunkturkomponente"},{"inline":true,"label":"schuldenbremse","permalink":"/dz-publikationsgraph/wiki/tags/schuldenbremse"},{"inline":true,"label":"produktionspotenzial","permalink":"/dz-publikationsgraph/wiki/tags/produktionspotenzial"},{"inline":true,"label":"fiskalregeln","permalink":"/dz-publikationsgraph/wiki/tags/fiskalregeln"},{"inline":true,"label":"reform","permalink":"/dz-publikationsgraph/wiki/tags/reform"}],"version":"current","frontMatter":{"title":"Ein Reformvorschlag f\xfcr die Konjunkturkomponente der Schuldenbremse","date":"2021-09-01","authors":["Dezernat Zukunft"],"cluster":"fiskalpolitik","tags":["konjunkturkomponente","schuldenbremse","produktionspotenzial","fiskalregeln","reform"],"edge_notes":"Erkl\xe4rt den Vorschlag aus dem Papier zu \'Warum die Konjunkturkomponente ihren Zweck nicht mehr erf\xfcllt\'","ignore":"yes"},"sidebar":"wikiSidebar","previous":{"title":"Reformen brauchen Kitas","permalink":"/dz-publikationsgraph/wiki/publikationen/reformen-brauchen-kitas"},"next":{"title":"Sovereign Debt Issuance and the Transformation of the Monetary Architecture in Prussia and the German Empire, 1740-1914","permalink":"/dz-publikationsgraph/wiki/publikationen/sovereign-debt-issuance-monetary-architecture-prussia-1740-1914"}}'),t=i(74848),s=i(28453);let a={title:"Ein Reformvorschlag f\xfcr die Konjunkturkomponente der Schuldenbremse",date:"2021-09-01",authors:["Dezernat Zukunft"],cluster:"fiskalpolitik",tags:["konjunkturkomponente","schuldenbremse","produktionspotenzial","fiskalregeln","reform"],edge_notes:"Erkl\xe4rt den Vorschlag aus dem Papier zu 'Warum die Konjunkturkomponente ihren Zweck nicht mehr erf\xfcllt'",ignore:"yes"},u="Ein Reformvorschlag f\xfcr die Konjunkturkomponente der Schuldenbremse",l={},d=[];function h(e){let n={h1:"h1",header:"header",p:"p",...(0,s.R)(),...e.components};return(0,t.jsxs)(t.Fragment,{children:[(0,t.jsx)(n.header,{children:(0,t.jsx)(n.h1,{id:"ein-reformvorschlag-f\xfcr-die-konjunkturkomponente-der-schuldenbremse",children:"Ein Reformvorschlag f\xfcr die Konjunkturkomponente der Schuldenbremse"})}),"\n",(0,t.jsx)(n.p,{children:"Was ist die Konjunkturkomponente? Die Konjunkturkomponente ist der Teil der Schuldenbremse, der die maximal zul\xe4ssige Nettokreditaufnahme (NKA) bei einer von der Normallage abweichenden\r\nwirtschaftlichen Entwicklung erhht oder verringert. Berechnet wird die Konjunkturkomponente, indem man die Differenz zwischen gegenwrtiger wirtschaftlicher Leistung (dem BIP) und dem geschtzten\r\nwirtschaftlichen Produktionspotenzial (der konomischen bersetzung des Begriffs Normallage) mit der Budgetsemielastizitt multipliziert. Die Budgetsemielastizitt bestimmt wie viel mehr (weniger)\r\nDefizit f\xfcr jeden Euro Unterauslastung (berauslastung) gemacht werden darf. Eine grafische\r\nDarstellung und weiterer Hintergrund dazu findet sich hier und im Kompendium zur Schuldenregel des\r\nBundes des BMFs."}),"\n",(0,t.jsx)(n.p,{children:"Wieso ist sie problematischfi Die derzeitige Ausgestaltung der Konjunkturkomponente weist mehrere\r\nProbleme auf. Gesetzlich bleiben die Inputs f\xfcr die Schtzung des Produktionspotenzials undefiniert.\r\nKorioth und Mller kritisieren das in ihrem Gutachten. Der Gesetzgeber htte die Definition der Inputs nicht der technischen Ebene berlassen sollen. Aus konomischer Sicht lsst sich nicht eindeutig\r\ndefinieren, wann eine Wirtschaft ihr Potenzial erreicht hat, also wann zum Beispiel das Arbeitspotenzial ausgeschpft ist (der erhebliche durch diese Unbestimmthei\xdft entstehende Spielraum ist ein Grund,\r\nweshalb die Delegation der Definition an die technische Ebene laut Gutachten problematisch ist). Man nimmt daher an, dass das Produktionspotenzial die in etwa der um konjunkturelle Einflsse bereinigten\r\nwirtschaftlichen Leistung der Vergangenhei\xdft entspricht. Auch die konjunkturellen Einflsse lassen sich jedoch nicht eindeutig bestimmen. Daher trifft man statistische Annahmen und bestimmt weitgehend\r\nper Annahme, welche Entwicklung unter konjunkturell verbucht wird und welche das Potenzial beeinflusst (mehr Detail dazu findet sich hier). Die amerikanische Notenbank sah einen der zentralen\r\nInputs f\xfcr die Potenzialrechnung, das Konzept der niedrigst m\xf6glichen Arbeitslosenquote NAWRU als so problematisch an, dass sie diesen Indikator 2020 gegen ein maximum employment Ziel ausgetauscht\r\nhat. Dar\xfcber hinaus m\xfcssen bei der Berechnung des Potenzials weitere politische Wertungen getroffen werden. Wie viele Frau\xdfen werden in der Zukunft wie viel arbeitenfi ist etwa eine Frage, deren Antwort\r\nauch davon abhngt, welche Gesellschaftspolitik verfolgt wird. Die Antwort darauf hat mageblichen\r\nEinfluss auf die Hhe des geschtzten Produktionspotenzials und damit auch auf die zulssige\r\nNettokreditaufnahme. Korioth et al. schlieen daraus: Es ist deshalb Aufgabe des parlamentarischen\r\nGesetzgebers, die Faktoren und die hinsichtlich dieser zu treffenden Annahmen festzulegen. 5 G-115 kommt dieser Aufgabe nur unzureichend nach."}),"\n",(0,t.jsx)(n.p,{children:"Wie sieht der Reformvorschlag ausfi Es werden drei kurzf\xfcristige Modifikationen vorgeschlagen, um einige der genannten Probleme abzuschwchen. Anstelle NAWRU, potenzielle Partizipationsrate (die\r\ndefiniert, welcher Anteil an der Bevlkerung am Arbeitsmarkt teilnimmt) und Arbeitsstunden ber eine\r\nFortschreibung ihrer vergangenen Trends zu definieren, gilt das Arbeitspotenzial als ausgeschpft, wenn:\r\n(1) keine Langzeitarbeitslosigkeit mehr vorherrscht,\r\n(2) der Rckstand der Frau\xdfen bei der\r\nArbeitsmarktpartizipation gegen\xfcber Mnnern halbiert ist (entspricht dem Niveau in Skandinavien) und\r\n(3) unf\xfcreiwillige und nicht-notwendige Teilzeit halbiert wurde. Der Gesetzgeber sollte aktiv ber die\r\nAnpassung dieser Inputs entschei\xdfden, um das bisherige Legitimationsdefizit zu beheben. Eine solche\r\nReform w\xfcrde die Kohrenz der Finanzpolitik erhhen, da der Gesetzgeber in der Verantwortung stnde, das von ihm gesetzte wirtschaftliche Potenzial auch tats\xe4chlich zu erm\xf6glichen. Auf Basis der \xf6\xf6ffentlich\r\nverf\xfcgbaren Berechnungsmethodik der EU-Kommission und ihrer Prognose vom Frhjahr 2021 w\xfcrde die Reform eine Erhhung der zulssigen NKA f\xfcr 2023 um knapp 20 Mrd. EUR bedeuten. Diese\r\nSchtzungen unterliegen aber signifikanten Schwankungen. Belastbare Zahlen bedrften einer\r\nBerechnung auf Basis der aktuellen Prognose der Bundesregierung mit dem Berechnungsverfahren der"}),"\n",(0,t.jsx)(n.p,{children:"1"}),"\n",(0,t.jsx)(n.p,{children:"\fBundesregierung (anstatt dem Code der EU-Kommission)."}),"\n",(0,t.jsx)(n.p,{children:"Wieso ist diese Reform finanzpolitisch nachhaltigfi Die gr\xf6\xdfte finanzpolitische Herausforderung ist heute die demografische Entwicklung. Eine zur\xfcckgehende Erwerbsbevlkerung steht mehr und mehr\r\nRentnerinnen und Rentnern gegen\xfcber, die demographische Abhngigkeitsquote soll von 36% in 2019 auf 52% in 2040 steigen. Knapp ein Drittel des Bundeshaushalts fliet (in nicht Corona Jahren) bereits in\r\nZuschsse zur gesetzlichen Rentenversicherung. Gleichzeitig leisten wir uns eine konomische\r\nAbhngigkeitsquote (das Verhltnis von Transferabhngigen zu Erwerbst\xe4tigen) von 62%. Zu viele\r\nMenschen k\xf6nnen trotz Arbeit ihren Lebensunterhalt nicht selbst verdienen, ber 10% der\r\nErwerbst\xe4tigen sind ausschlie\xdflich geringfgig beschftigt. Angesichts dessen schei\xdfnt es widersinnig im\r\nNamen einer nachhaltigen Finanzpolitik das Arbeitspotenzial an der Vergangenhei\xdft auszurichten, anstatt sich darum zu bemhen, dass jede Erwerbsperson die Chance hat den eigenen Lebensunterhalt zu\r\nverdienen. Denn wer ein gutes Einkommen hat zahlt Steuern, kann f\xfcr das Alter vorsorgen und ist nicht auf Sozialleistungen angewiesen. Mehr zu einer auf die heutigen Herausforderungen angepassten\r\nFinanzpolitik findet sich hier. Zuletzt behlt die Fiskalpolitik mit diesem Reformvorschlag weiterhin die\r\nInflation im Blick, da das zulssige Defizit mit Bezug auf das wirtschaftliche Potenzial definiert wird."}),"\n",(0,t.jsx)(n.p,{children:"Ist die Reform rechtlich m\xf6glichfi Ja. Korioth et al. stellen in ihrem Gutachten fest, dass die Umsetzung ohne rechtliche Anpassung umsetzbar wre. Die momentane einfachgesetzliche Ausgestaltung der\r\nSchuldenbremse halten die Gutachter jedoch, wie bereits erw\xe4hnt, f\xfcr problematisch und empfehlen au\xdferdem, Abweichungen von der Europischen Methode zur Konjunkturbereinigung klarzustellen.\r\nDaher wre ihrer Ansicht nach eine rechtliche Umsetzung des Vorschlags auf einfachgesetzlicher Ebene vorzuziehen. Der Bestimmung\r\ndes\r\nProduktionspotenzials durch das Parlament seien jedoch Grenzen gesetzt. So drfe das Parlament nicht die Ideallage zur Normallage erklren, letztere m\xfcsse tats\xe4chlich erreichbar sein. Die Politik stnde also\r\nin der Verantwortung, das von ihr selbst veranschlagte Potenzial -ggf. durch Reformen- auch zu erm\xf6glichen. Es w\xfcrde nun also ein Anreiz bestehen, Reformen auch umzusetzen. Zudem seien laut\r\nKorioth et al. auch Verschuldungsspielrume limitiert. berschreitet das Defizit 1,5% des BIPs m\xfcsse es\r\nKonjunktur gerecht zur\xfcckgef\xfchrt werden."}),"\n",(0,t.jsx)(n.p,{children:"grundlegenden Annahmen"}),"\n",(0,t.jsx)(n.p,{children:"zur Berechnung"}),"\n",(0,t.jsx)(n.p,{children:"der"}),"\n",(0,t.jsx)(n.p,{children:"Sollte eine Anpassung der Potenzialschtzung nicht im Europischen Kontext geschehenfi Die\r\nPotenzialschtzung wird auch f\xfcr die Europischen Fiskalregeln genutzt (im Kontext dieser flieen si aber nur in eine qualitative Beurteilung mit ein). Die Antwort auf die Frage hngt vor allem von politischen und\r\nggf. konomischen berlegungen ab. Es wre auch m\xf6glich die Inputs zur Berechnung nur in\r\nDeutschland anzupassen. Wie erw\xe4hnt wre in diesem Fall eine einfach gesetzliche Anpassung wnschenswert. Zudem k\xf6nnen geringfgige Anpassungen der Berechnungen im Rahmen des\r\neuropischen Verfahrens genehmigt werden. Auf der anderen Seite sind alle Mitgliedsstaaten im\r\nRahmen des Stabilitts- und Wachstumspakts von der gleichen Problematik betroffen, da f\xfcr jeden\r\nMitgliedsstaat ein Produktionspotenzial geschtzt wird. Zudem stellt sich auch auf europischer Ebene die Frage, wie der Stabilitts- und Wachstumspakt weiterentwickelt werden sollte, um den heutigen\r\nHerausforderungen gerecht zu werden."}),"\n",(0,t.jsx)(n.p,{children:"Lst dieser Vorschlag alle Probleme der heutigen Finanzpolitikfi Nein. Er kann mit seinem Fokus auf\r\nVollauslastung dazu beitragen, die Schuldenbremse wieder, wie in der ursprnglichen\r\nGesetzesbegrndung angedacht, auf finanzielle Nachhaltigkeit auszurichten und das Legitimationsdefizit reduzieren. Dar\xfcber hinaus bedarf es langf\xfcristiger Investitionen, insbesondere auf kommunaler Ebene\r\nund zur Dekarbonisierung. Zu diesem Zweck eignet sich ein klar abgegrenzter Investitionsfonds, der ber einen mittelf\xfcristigen Zeitraum Mittel bereitstellt."}),"\n",(0,t.jsx)(n.p,{children:"2"})]})}function o(e={}){let{wrapper:n}={...(0,s.R)(),...e.components};return n?(0,t.jsx)(n,{...e,children:(0,t.jsx)(h,{...e})}):h(e)}},28453(e,n,i){i.d(n,{R:()=>a,x:()=>u});var r=i(96540);let t={},s=r.createContext(t);function a(e){let n=r.useContext(s);return r.useMemo(function(){return"function"==typeof e?e(n):{...n,...e}},[n,e])}function u(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(t):e.components||t:a(e.components),r.createElement(s.Provider,{value:n},e.children)}}}]);